import {
	entityResponse,
	listEntitiesQuery,
	listEntitiesResponse,
	updateEntityBody,
} from "@mappa-ai/contracts/v1/entities";
import { ConduitError } from "../errors";
import type { Entity, ListEntitiesResponse } from "../types";
import type { Transport } from "./transport";
import { parseReq, parseRes } from "./validate";

export type ListEntitiesOptions = {
	limit?: number;
	cursor?: string;
	requestId?: string;
	signal?: AbortSignal;
};

export class EntitiesResource {
	private readonly transport: Transport;

	constructor(transport: Transport) {
		this.transport = transport;
	}

	async get(
		entityId: string,
		opts?: { requestId?: string; signal?: AbortSignal },
	): Promise<Entity> {
		if (!entityId)
			throw new ConduitError("entityId must be a non-empty string", {
				code: "invalid_request",
			});
		const res = await this.transport.request<Entity>({
			method: "GET",
			path: `/v1/entities/${encodeURIComponent(entityId)}`,
			requestId: opts?.requestId,
			retryable: true,
			signal: opts?.signal,
		});
		return parseRes(entityResponse, res.data, "entities.get");
	}

	async list(opts?: ListEntitiesOptions): Promise<ListEntitiesResponse> {
		const query = parseReq(
			listEntitiesQuery,
			{ cursor: opts?.cursor, limit: opts?.limit },
			"entities.list query",
		);

		const res = await this.transport.request<ListEntitiesResponse>({
			method: "GET",
			path: "/v1/entities",
			query: {
				limit: String(query.limit),
				...(query.cursor ? { cursor: query.cursor } : {}),
			},
			requestId: opts?.requestId,
			retryable: true,
			signal: opts?.signal,
		});
		return parseRes(listEntitiesResponse, res.data, "entities.list");
	}

	async *listAll(
		opts?: Omit<ListEntitiesOptions, "cursor">,
	): AsyncIterable<Entity> {
		let cursor: string | undefined;
		let hasMore = true;
		while (hasMore) {
			// biome-ignore lint/performance/noAwaitInLoops: cursor-based pagination is inherently sequential
			const page = await this.list({ ...opts, cursor });
			for (const entity of page.entities) {
				yield entity;
			}
			cursor = page.cursor ?? undefined;
			hasMore = page.hasMore;
		}
	}

	async update(
		entityId: string,
		body: { label?: string | null },
		opts?: { requestId?: string; signal?: AbortSignal },
	): Promise<Entity> {
		if (!entityId)
			throw new ConduitError("entityId must be a non-empty string", {
				code: "invalid_request",
			});
		const payload = parseReq(updateEntityBody, body, "entities.update body");
		const res = await this.transport.request<Entity>({
			body: payload,
			method: "PATCH",
			path: `/v1/entities/${encodeURIComponent(entityId)}`,
			requestId: opts?.requestId,
			retryable: true,
			signal: opts?.signal,
		});
		return parseRes(entityResponse, res.data, "entities.update");
	}
}
