import { z } from "zod";
import { reportTemplates } from "./reports";

// ═══════════════════════════════════════════════════════════════════════
// RETENTION SCHEMAS
// ═══════════════════════════════════════════════════════════════════════

export const retentionInfo = z.object({
	daysRemaining: z
		.number()
		.int()
		.nullable()
		.describe("Days until expiry (null if locked or deleted)"),
	expiresAt: z.iso
		.datetime()
		.nullable()
		.describe("When the file will expire (null if locked)"),
	locked: z
		.boolean()
		.describe("Whether the file is locked from automatic deletion"),
});
export type RetentionInfo = z.infer<typeof retentionInfo>;

export const retentionUpdateBody = z.object({
	lock: z.boolean().describe("Set to true to lock, false to unlock"),
});
export type RetentionUpdateBody = z.infer<typeof retentionUpdateBody>;

export const retentionUpdateResponse = z.object({
	mediaId: z.string(),
	message: z.string(),
	retentionLock: z.boolean(),
});
export type RetentionUpdateResponse = z.infer<typeof retentionUpdateResponse>;

// ═══════════════════════════════════════════════════════════════════════
// FILE SCHEMAS
// ═══════════════════════════════════════════════════════════════════════

export const mediaSource = z.enum([
	"NOTETAKER",
	"MANUAL_UPLOAD",
	"PLAYGROUND",
	"SDK",
]);
export type MediaSource = z.infer<typeof mediaSource>;

export const mediaProcessingStatus = z.enum([
	"PENDING",
	"PROCESSING",
	"COMPLETED",
	"FAILED",
]);
export type MediaProcessingStatus = z.infer<typeof mediaProcessingStatus>;

export const manualUploadReportTemplates = z.preprocess(
	(val) => (typeof val === "string" ? [val] : val),
	z
		.array(reportTemplates)
		.min(1)
		.max(2)
		.refine((value) => new Set(value).size === value.length, {
			message: "Report templates must be unique",
		}),
);
export type ManualUploadReportTemplate = z.infer<
	typeof manualUploadReportTemplates
>[number];

export const uploadResponse = z.object({
	contentType: z.string(),
	createdByApiKeyId: z.string().nullable(),
	createdByUserId: z.string(),
	createdAt: z.string(),
	durationSeconds: z.number().nullish(),
	label: z.string(),
	mediaId: z.string(),
	source: mediaSource,
	sizeBytes: z.number().int().nullish(),
	workspaceId: z.string(),
});
export type UploadResponse = z.infer<typeof uploadResponse>;

export const fileResponse = z.object({
	contentType: z.string(),
	createdByApiKeyId: z.string().nullable(),
	createdByUserId: z.string(),
	createdAt: z.iso.datetime(),
	durationSeconds: z.number().nullish(),
	hasReports: z.boolean(),
	label: z.string(),
	lastUsedAt: z.iso.datetime().nullable(),
	mediaId: z.string(),
	processingStatus: mediaProcessingStatus,
	retention: retentionInfo,
	source: mediaSource,
	sizeBytes: z.number().int().nullish(),
	workspaceId: z.string(),
});
export type FileResponse = z.infer<typeof fileResponse>;

export const listFilesQuery = z.object({
	createdAfter: z.iso.datetime().optional(),
	createdByUserId: z.string().optional(),
	cursor: z.string().optional(),
	includeDeleted: z.coerce.boolean().default(false),
	limit: z.coerce.number().int().min(1).max(100).default(20),
	search: z.string().trim().min(1).max(200).optional(),
});
export type ListFilesQuery = z.infer<typeof listFilesQuery>;

export const listFilesResponse = z.object({
	files: z.array(fileResponse),
	hasMore: z.boolean(),
	nextCursor: z.string().nullable(),
});
export type ListFilesResponse = z.infer<typeof listFilesResponse>;

export const transcriptUtterance = z.object({
	endSeconds: z.number(),
	speakerIndex: z.number().int().nonnegative(),
	startSeconds: z.number(),
	text: z.string(),
});
export type TranscriptUtterance = z.infer<typeof transcriptUtterance>;

export const mediaSpeaker = z.object({
	entityId: z.string().nullable(),
	entityLabel: z.string().nullable(),
	speakerIndex: z.number().int().nonnegative(),
	totalDurationSeconds: z.number().nonnegative(),
	utteranceCount: z.number().int().nonnegative(),
});
export type MediaSpeaker = z.infer<typeof mediaSpeaker>;

export const fileDetailResponse = fileResponse.extend({
	speakers: z.array(mediaSpeaker),
	transcription: z.object({
		durationSeconds: z.number().nonnegative(),
		speakerCount: z.number().int().nonnegative(),
		utterances: z.array(transcriptUtterance),
	}),
});
export type FileDetailResponse = z.infer<typeof fileDetailResponse>;

export const audioUrlResponse = z.object({
	url: z.string().url(),
});
export type AudioUrlResponse = z.infer<typeof audioUrlResponse>;

export const audioMetadataWarningBody = z.object({
	metadataDurationSeconds: z.number().nonnegative(),
	transcriptDurationSeconds: z.number().nonnegative(),
});
export type AudioMetadataWarningBody = z.infer<typeof audioMetadataWarningBody>;

export const audioMetadataWarningResponse = z.object({
	enqueuedRemediation: z.boolean(),
	mediaId: z.string(),
	severity: z.enum(["minor", "major"]),
});
export type AudioMetadataWarningResponse = z.infer<
	typeof audioMetadataWarningResponse
>;

export const deleteResponse = z.object({
	deleted: z.literal(true),
	mediaId: z.string(),
});
export type DeleteResponse = z.infer<typeof deleteResponse>;

// ═══════════════════════════════════════════════════════════════════════
// ERROR SCHEMAS
// ═══════════════════════════════════════════════════════════════════════

export const goneError = z.object({
	deletedAt: z.iso.datetime(),
	error: z.literal("gone"),
	message: z.string(),
});
export type GoneError = z.infer<typeof goneError>;

export const notFoundError = z.object({
	error: z.object({
		code: z.literal("not_found"),
		message: z.string(),
	}),
});
export type NotFoundError = z.infer<typeof notFoundError>;

export const unsupportedMediaTypeError = z.object({
	error: z.object({
		code: z.literal("unsupported_media_type"),
		message: z.string(),
	}),
});
export type UnsupportedMediaTypeError = z.infer<
	typeof unsupportedMediaTypeError
>;
