import {
	deleteResponse,
	fileResponse,
	listFilesQuery,
	listFilesResponse,
	retentionUpdateResponse,
	uploadResponse,
} from "@mappa-ai/contracts/v1/files";
import {
	ConduitError,
	InvalidSourceError,
	UnsupportedRuntimeError,
} from "../errors";
import type {
	FileDeleteReceipt,
	ListFilesResponse,
	MediaFile,
	MediaObject,
	MediaUploadRequest,
	RetentionLockResult,
} from "../types";
import { DEFAULT_MAX_SOURCE_BYTES, materializeSource } from "./source";
import type { Transport } from "./transport";
import { parseReq, parseRes } from "./validate";

const LABEL_SUFFIX_REGEX = /(\.[^.]+)+$/;

type ListFilesOptions = {
	limit?: number;
	cursor?: string;
	includeDeleted?: boolean;
	requestId?: string;
	signal?: AbortSignal;
};

class FilesResource {
	private readonly transport: Transport;
	private readonly fetchImpl: typeof fetch;
	private readonly timeoutMs: number;
	private readonly maxSourceBytes: number;

	constructor(
		transport: Transport,
		opts?: {
			fetchImpl?: typeof fetch;
			timeoutMs?: number;
			maxSourceBytes?: number;
		},
	) {
		this.transport = transport;
		this.fetchImpl = opts?.fetchImpl ?? fetch;
		this.timeoutMs = opts?.timeoutMs ?? 300000;
		this.maxSourceBytes = opts?.maxSourceBytes ?? DEFAULT_MAX_SOURCE_BYTES;
	}

	async upload(req: MediaUploadRequest): Promise<MediaObject> {
		if (typeof FormData === "undefined") {
			throw new UnsupportedRuntimeError(
				"FormData is not available in this runtime; cannot perform multipart upload",
				{ code: "unsupported_runtime" },
			);
		}

		const source = validateUploadSource(req);
		const { file, label: rawLabel } = await materializeSource(source, {
			fetchImpl: this.fetchImpl,
			maxSourceBytes: this.maxSourceBytes,
			signal: req.signal,
			timeoutMs: this.timeoutMs,
		});
		const label = filesLabel(rawLabel);
		if (!label) {
			throw new InvalidSourceError("label is required", {
				code: "invalid_source",
			});
		}

		const form = new FormData();
		form.append("file", file, label);
		form.append("label", label);

		const res = await this.transport.request<MediaObject>({
			body: form,
			idempotencyKey: req.idempotencyKey,
			method: "POST",
			path: "/v1/files",
			requestId: req.requestId,
			retryable: true,
			signal: req.signal,
		});
		return parseRes(uploadResponse, res.data, "files.upload");
	}

	async get(
		mediaId: string,
		opts?: { requestId?: string; signal?: AbortSignal },
	): Promise<MediaFile> {
		if (!mediaId) {
			throw new ConduitError("mediaId is required", {
				code: "invalid_request",
			});
		}
		const res = await this.transport.request<MediaFile>({
			method: "GET",
			path: `/v1/files/${encodeURIComponent(mediaId)}`,
			requestId: opts?.requestId,
			retryable: true,
			signal: opts?.signal,
		});
		return parseRes(fileResponse, res.data, "files.get");
	}

	async list(opts?: ListFilesOptions): Promise<ListFilesResponse> {
		const query = parseReq(
			listFilesQuery,
			{
				cursor: opts?.cursor,
				includeDeleted: opts?.includeDeleted,
				limit: opts?.limit,
			},
			"files.list query",
		) as {
			cursor?: string;
			includeDeleted: boolean;
			limit: number;
		};

		const res = await this.transport.request<ListFilesResponse>({
			method: "GET",
			path: "/v1/files",
			query: {
				limit: String(query.limit),
				...(query.cursor ? { cursor: query.cursor } : {}),
				includeDeleted: String(query.includeDeleted),
			},
			requestId: opts?.requestId,
			retryable: true,
			signal: opts?.signal,
		});
		return parseRes(listFilesResponse, res.data, "files.list");
	}

	async *listAll(
		opts?: Omit<ListFilesOptions, "cursor">,
	): AsyncIterable<MediaFile> {
		let cursor: string | undefined;
		let hasMore = true;
		while (hasMore) {
			// biome-ignore lint/performance/noAwaitInLoops: cursor-based pagination is inherently sequential
			const page = await this.list({ ...opts, cursor });
			for (const file of page.files) {
				yield file;
			}
			cursor = page.nextCursor ?? undefined;
			hasMore = page.hasMore;
		}
	}

	async setRetentionLock(
		mediaId: string,
		locked: boolean,
		opts?: { requestId?: string; signal?: AbortSignal },
	): Promise<RetentionLockResult> {
		if (!mediaId) {
			throw new ConduitError("mediaId is required", {
				code: "invalid_request",
			});
		}
		const res = await this.transport.request<RetentionLockResult>({
			body: { lock: locked },
			method: "PATCH",
			path: `/v1/files/${encodeURIComponent(mediaId)}/retention`,
			requestId: opts?.requestId,
			retryable: true,
			signal: opts?.signal,
		});
		return parseRes(
			retentionUpdateResponse,
			res.data,
			"files.setRetentionLock",
		);
	}

	async delete(
		mediaId: string,
		opts?: {
			idempotencyKey?: string;
			requestId?: string;
			signal?: AbortSignal;
		},
	): Promise<FileDeleteReceipt> {
		if (!mediaId) {
			throw new ConduitError("mediaId is required", {
				code: "invalid_request",
			});
		}
		const res = await this.transport.request<FileDeleteReceipt>({
			idempotencyKey: opts?.idempotencyKey,
			method: "DELETE",
			path: `/v1/files/${encodeURIComponent(mediaId)}`,
			requestId: opts?.requestId,
			retryable: true,
			signal: opts?.signal,
		});
		return parseRes(deleteResponse, res.data, "files.delete");
	}
}

function filesLabel(value: string) {
	const label = value.replace(LABEL_SUFFIX_REGEX, "").trim();
	if (label) return label;
	return "";
}

function validateUploadSource(req: MediaUploadRequest) {
	const keys = ["file", "url", "path"].filter((key) => key in req);
	if (keys.length === 1) return req;
	throw new InvalidSourceError(
		"upload() must include exactly one of file, url, or path",
		{ code: "invalid_source" },
	);
}

export type { ListFilesOptions };
export { FilesResource };
