import { z } from "zod";

const jobStatus = z.enum([
	"queued",
	"running",
	"succeeded",
	"failed",
	"canceled",
]);
type JobStatus = z.infer<typeof jobStatus>;
const jobStage = z.enum([
	"uploaded",
	"queued",
	"transcoding",
	"extracting",
	"scoring",
	"rendering",
	"finalizing",
]);
type JobStage = z.infer<typeof jobStage>;
const jobResponse = z.object({
	createdAt: z.string(),
	credits: z
		.object({
			reservationStatus: z.enum(["active", "released", "applied"]).nullable(),
			reservedCredits: z.number().nullable(),
		})
		.optional(),
	error: z
		.object({
			code: z.string(),
			details: z.unknown().optional(),
			message: z.string(),
			retryable: z.boolean().optional(),
		})
		.optional(),
	id: z.string(),
	matchingId: z.string().optional(),
	progress: z.number().optional(),
	releasedCredits: z.number().nullable().optional(),
	reportId: z.string().optional(),
	stage: z
		.enum([
			"uploaded",
			"queued",
			"transcoding",
			"extracting",
			"scoring",
			"rendering",
			"finalizing",
		])
		.optional(),
	status: z.enum(["queued", "running", "succeeded", "failed", "canceled"]),
	type: z.enum(["report.generate", "matching.generate"]),
	updatedAt: z.string(),
	usage: z
		.object({
			creditsDiscounted: z.number().optional(),
			creditsNetUsed: z.number(),
			creditsUsed: z.number(),
			durationMs: z.number().optional(),
			modelVersion: z.string().optional(),
		})
		.optional(),
});
type JobResponse = z.infer<typeof jobResponse>;
const streamEventType = z.enum(["status", "stage", "terminal", "heartbeat"]);
type StreamEventType = z.infer<typeof streamEventType>;

/**
 * Base SSE event structure with event ID for Last-Event-ID support.
 */
const baseStreamEvent = z.object({
	id: z.string().describe("Monotonically increasing event ID for resumption"),
});
const statusStreamEvent = baseStreamEvent.extend({
	data: z.object({
		job: jobResponse,
		progress: z.number().optional(),
		stage: jobStage.optional(),
		status: jobStatus,
	}),
	event: z.literal("status"),
});
type StatusStreamEvent = z.infer<typeof statusStreamEvent>;
const stageStreamEvent = baseStreamEvent.extend({
	data: z.object({
		job: jobResponse,
		progress: z.number().optional(),
		stage: jobStage,
	}),
	event: z.literal("stage"),
});
type StageStreamEvent = z.infer<typeof stageStreamEvent>;
const terminalStreamEvent = baseStreamEvent.extend({
	data: z.object({
		error: z
			.object({
				code: z.string(),
				message: z.string(),
			})
			.optional(),
		job: jobResponse,
		matchingId: z.string().optional(),
		reportId: z.string().optional(),
		status: z.enum(["succeeded", "failed", "canceled"]),
	}),
	event: z.literal("terminal"),
});
type TerminalStreamEvent = z.infer<typeof terminalStreamEvent>;
const heartbeatStreamEvent = baseStreamEvent.extend({
	data: z.object({
		timestamp: z.string(),
	}),
	event: z.literal("heartbeat"),
});
type HeartbeatStreamEvent = z.infer<typeof heartbeatStreamEvent>;
const jobStreamEvent = z.discriminatedUnion("event", [
	statusStreamEvent,
	stageStreamEvent,
	terminalStreamEvent,
	heartbeatStreamEvent,
]);
type JobStreamEvent = z.infer<typeof jobStreamEvent>;
const streamQueryParams = z.object({
	timeout: z.coerce
		.number()
		.min(1000)
		.max(300000)
		.default(300000)
		.describe("Stream timeout in milliseconds (default: 300000, max: 300000)"),
});
type StreamQueryParams = z.infer<typeof streamQueryParams>;

export type {
	HeartbeatStreamEvent,
	JobResponse,
	JobStage,
	JobStatus,
	JobStreamEvent,
	StageStreamEvent,
	StatusStreamEvent,
	StreamEventType,
	StreamQueryParams,
	TerminalStreamEvent,
};
export {
	heartbeatStreamEvent,
	jobResponse,
	jobStage,
	jobStatus,
	jobStreamEvent,
	stageStreamEvent,
	statusStreamEvent,
	streamEventType,
	streamQueryParams,
	terminalStreamEvent,
};
