import {
	createJobBody,
	jobReceipt,
	matchingAnalysisResponse,
} from "@mappa-ai/contracts/v1/matching";
import { ConduitError } from "../errors";
import type {
	Job,
	JobEvent,
	JobStage,
	MatchingAnalysisCreateJobRequest,
	MatchingAnalysisEntitySource,
	MatchingAnalysisForOutputType,
	MatchingAnalysisJobReceipt,
	MatchingAnalysisResponse,
	MatchingAnalysisRunHandle,
	MatchingSubjectRef,
	TargetSelector,
	WaitOptions,
} from "../types";
import { randomId } from "../utils";
import type { JobsResource } from "./jobs";
import type { Transport } from "./transport";
import { parseReq, parseRes } from "./validate";

type RawTargetSelector = {
	strategy:
		| "dominant"
		| "timerange"
		| "entity_id"
		| "magic_hint"
		| "speaker_index";
	on_miss?: "fallback_dominant" | "error";
	entity_id?: string | null;
	hint?: string | null;
	speaker_index?: number | null;
	timerange?: {
		start_seconds?: number | null;
		end_seconds?: number | null;
	} | null;
};

type RawMatchingSubjectRef =
	| {
			type: "entity_id";
			entityId: string;
	  }
	| {
			type: "media_target";
			mediaId: string;
			selector: RawTargetSelector;
	  };

type RawMatchingResolvedSubject = {
	entityId?: string;
	resolvedLabel?: string | null;
	source: RawMatchingSubjectRef;
};

type RawMatchingAnalysis = {
	context: "behavioral_compatibility";
	createdAt: string;
	group: RawMatchingResolvedSubject[];
	id: string;
	jobId?: string;
	label?: string;
	markdown?: string | null;
	json?: MatchingAnalysisResponse["output"]["json"];
	target: RawMatchingResolvedSubject;
};

class MatchingAnalysisResource {
	private readonly transport: Transport;
	private readonly jobs: JobsResource;

	constructor(transport: Transport, jobs: JobsResource) {
		this.transport = transport;
		this.jobs = jobs;
	}

	create(
		req: MatchingAnalysisCreateJobRequest,
	): Promise<MatchingAnalysisJobReceipt> {
		return this.createJob(req);
	}

	async createJob(
		req: MatchingAnalysisCreateJobRequest,
	): Promise<MatchingAnalysisJobReceipt> {
		validateMatchingRequest(req);
		const idempotencyKey = req.idempotencyKey ?? randomId("idem");
		const body = parseReq(
			createJobBody,
			this.normalizeBody(req),
			"matching.create body",
		);
		const res = await this.transport.request<
			Omit<MatchingAnalysisJobReceipt, "handle">
		>({
			body,
			idempotencyKey,
			method: "POST",
			path: "/v1/matching/jobs",
			requestId: req.requestId,
			retryable: true,
			signal: req.signal,
		});

		const receiptData = parseRes(jobReceipt, res.data, "matching.create") as {
			estimatedWaitSec?: number;
			jobId: string;
			stage?: string;
			status: "queued" | "running";
		};
		const receipt: MatchingAnalysisJobReceipt = {
			...receiptData,
			requestId: res.requestId ?? res.data.requestId,
			stage: toJobStage(receiptData.stage),
		};
		receipt.handle = this.makeHandle(receipt.jobId);
		return receipt;
	}

	async get(
		matchingId: string,
		opts?: { requestId?: string; signal?: AbortSignal },
	): Promise<MatchingAnalysisResponse> {
		const res = await this.transport.request<unknown>({
			method: "GET",
			path: `/v1/matching/${encodeURIComponent(matchingId)}`,
			requestId: opts?.requestId,
			retryable: true,
			signal: opts?.signal,
		});
		return toMatchingAnalysis(
			parseRes(matchingAnalysisResponse, res.data, "matching.get"),
		);
	}

	async getByJob(
		jobId: string,
		opts?: { requestId?: string; signal?: AbortSignal },
	): Promise<MatchingAnalysisResponse | null> {
		const res = await this.transport.request<unknown>({
			method: "GET",
			path: `/v1/matching/by-job/${encodeURIComponent(jobId)}`,
			requestId: opts?.requestId,
			retryable: true,
			signal: opts?.signal,
		});
		if (res.data === null) return null;
		return toMatchingAnalysis(
			parseRes(matchingAnalysisResponse, res.data, "matching.getByJob"),
		);
	}

	async generate(
		req: MatchingAnalysisCreateJobRequest,
		opts?: { wait?: WaitOptions },
	): Promise<MatchingAnalysisForOutputType> {
		const receipt = await this.createJob(req);
		if (!receipt.handle)
			throw new ConduitError("Job receipt is missing handle", {
				code: "invalid_response",
			});
		return receipt.handle.wait(opts?.wait);
	}

	makeHandle(jobId: string): MatchingAnalysisRunHandle {
		return {
			cancel: (): Promise<Job> => this.jobs.cancel(jobId),
			job: (): Promise<Job> => this.jobs.get(jobId),
			jobId,
			matching: () =>
				this.getByJob(jobId) as Promise<MatchingAnalysisForOutputType | null>,
			stream: (opts?: {
				signal?: AbortSignal;
				onEvent?: (e: JobEvent) => void;
			}) => this.jobs.stream(jobId, opts),
			wait: async (
				opts?: WaitOptions,
			): Promise<MatchingAnalysisForOutputType> => {
				const terminal = await this.jobs.wait(jobId, opts);
				const matchingId = terminal.matchingId;
				if (!matchingId) {
					throw new ConduitError(
						`Job ${jobId} succeeded but no matching id was returned`,
						{ code: "invalid_response" },
					);
				}
				return this.get(matchingId) as Promise<MatchingAnalysisForOutputType>;
			},
		};
	}

	private normalizeBody(
		req: MatchingAnalysisCreateJobRequest,
	): Record<string, unknown> {
		return {
			context: req.context,
			group: req.group.map((item) => this.normalizeEntitySource(item)),
			idempotencyKey: req.idempotencyKey,
			label: req.label,
			target: this.normalizeEntitySource(req.target),
			webhook: req.webhook,
		};
	}

	private normalizeEntitySource(
		source: MatchingAnalysisEntitySource,
	): Record<string, unknown> {
		if (isEntitySource(source)) {
			return {
				entityId: source.entityId,
				type: "entity_id",
			};
		}
		return {
			mediaId: source.mediaId,
			selector: this.normalizeTarget(source.selector),
			type: "media_target",
		};
	}

	private normalizeTarget(target: TargetSelector): Record<string, unknown> {
		if (target.strategy === "dominant") {
			return {
				strategy: target.strategy,
				...(target.onMiss ? { on_miss: target.onMiss } : {}),
			};
		}

		if (target.strategy === "timerange") {
			return {
				strategy: target.strategy,
				...(target.onMiss ? { on_miss: target.onMiss } : {}),
				timerange: {
					end_seconds: target.timeRange?.endSeconds ?? null,
					start_seconds: target.timeRange?.startSeconds ?? null,
				},
			};
		}

		if (target.strategy === "entity_id") {
			return {
				strategy: target.strategy,
				...(target.onMiss ? { on_miss: target.onMiss } : {}),
				entity_id: target.entityId,
			};
		}

		if (target.strategy === "speaker_index") {
			return {
				strategy: target.strategy,
				...(target.onMiss ? { on_miss: target.onMiss } : {}),
				speaker_index: target.speakerIndex,
			};
		}

		return {
			strategy: target.strategy,
			...(target.onMiss ? { on_miss: target.onMiss } : {}),
			hint: target.hint,
		};
	}
}

function validateMatchingRequest(req: MatchingAnalysisCreateJobRequest): void {
	if (req.context !== "behavioral_compatibility") {
		throw new ConduitError("context must be behavioral_compatibility", {
			code: "invalid_request",
		});
	}

	if (req.group.length < 1) {
		throw new ConduitError("group must include at least one subject", {
			code: "invalid_request",
		});
	}

	const ids = new Set<string>();
	for (const item of [req.target, ...req.group]) {
		if (!isEntitySource(item)) {
			if (!item.mediaId.trim()) {
				throw new ConduitError("mediaId is required", {
					code: "invalid_request",
				});
			}
			validateTarget(item.selector);
			continue;
		}

		if (!item.entityId.trim()) {
			throw new ConduitError("entityId is required", {
				code: "invalid_request",
			});
		}

		if (ids.has(item.entityId)) {
			throw new ConduitError(
				"target and group must reference different direct entity IDs",
				{
					code: "invalid_request",
				},
			);
		}
		ids.add(item.entityId);
	}
}

function isEntitySource(
	source: MatchingAnalysisEntitySource,
): source is Extract<MatchingSubjectRef, { entityId: string }> {
	return "entityId" in source;
}

function toMatchingAnalysis(
	matching: RawMatchingAnalysis,
): MatchingAnalysisResponse {
	return {
		context: matching.context,
		createdAt: matching.createdAt,
		group: matching.group.map((subject) => ({
			entityId: subject.entityId,
			resolvedLabel: subject.resolvedLabel,
			source: toSubjectRef(subject.source),
		})),
		id: matching.id,
		jobId: matching.jobId,
		label: matching.label,
		output: {
			json: matching.json ?? null,
			markdown: matching.markdown ?? null,
		},
		target: {
			entityId: matching.target.entityId,
			resolvedLabel: matching.target.resolvedLabel,
			source: toSubjectRef(matching.target.source),
		},
	};
}

function toSubjectRef(source: RawMatchingSubjectRef): MatchingSubjectRef {
	if (source.type === "entity_id") {
		return { entityId: source.entityId };
	}

	return {
		mediaId: source.mediaId,
		selector: toTargetSelector(source.selector),
	};
}

function toTargetSelector(selector: RawTargetSelector): TargetSelector {
	if (selector.strategy === "dominant") {
		return {
			onMiss: selector.on_miss,
			strategy: "dominant",
		};
	}

	if (selector.strategy === "timerange") {
		return {
			onMiss: selector.on_miss,
			strategy: "timerange",
			timeRange: {
				endSeconds: selector.timerange?.end_seconds ?? undefined,
				startSeconds: selector.timerange?.start_seconds ?? undefined,
			},
		};
	}

	if (selector.strategy === "entity_id") {
		return {
			entityId: selector.entity_id ?? "",
			onMiss: selector.on_miss,
			strategy: "entity_id",
		};
	}

	if (selector.strategy === "speaker_index") {
		return {
			onMiss: selector.on_miss,
			speakerIndex: selector.speaker_index ?? 0,
			strategy: "speaker_index",
		};
	}

	return {
		hint: selector.hint ?? "",
		onMiss: selector.on_miss,
		strategy: "magic_hint",
	};
}

function validateTarget(target: TargetSelector): void {
	if (target.strategy === "timerange") {
		validateTimerangeTarget(target.timeRange);
		return;
	}

	if (target.strategy === "entity_id" && !target.entityId.trim()) {
		throw new ConduitError("target.entityId is required for entity_id", {
			code: "invalid_request",
		});
	}

	if (
		target.strategy === "speaker_index" &&
		(!Number.isInteger(target.speakerIndex) || target.speakerIndex < 0)
	) {
		throw new ConduitError(
			"target.speakerIndex is required for speaker_index",
			{
				code: "invalid_request",
			},
		);
	}

	if (target.strategy === "magic_hint" && !target.hint.trim()) {
		throw new ConduitError("target.hint is required for magic_hint", {
			code: "invalid_request",
		});
	}
}

function validateTimerangeTarget(
	timeRange: { startSeconds?: number; endSeconds?: number } | undefined,
) {
	if (!timeRange) {
		throw new ConduitError("target.timeRange is required for timerange", {
			code: "invalid_request",
		});
	}

	const start = timeRange.startSeconds;
	const end = timeRange.endSeconds;
	if (start === undefined && end === undefined) {
		throw new ConduitError(
			"target.timeRange must include startSeconds or endSeconds",
			{ code: "invalid_request" },
		);
	}
	if (start !== undefined && end !== undefined && !(start < end)) {
		throw new ConduitError(
			"target.timeRange.startSeconds must be less than endSeconds",
			{ code: "invalid_request" },
		);
	}
}

function toJobStage(stage: string | undefined): JobStage | undefined {
	if (!stage) return;
	if (
		stage === "uploaded" ||
		stage === "queued" ||
		stage === "transcoding" ||
		stage === "extracting" ||
		stage === "scoring" ||
		stage === "rendering" ||
		stage === "finalizing"
	) {
		return stage;
	}
}

export { MatchingAnalysisResource };
