import { ConduitError, WebhookVerificationError } from "../errors";

function isObject(v: unknown): v is Record<string, unknown> {
	return v !== null && typeof v === "object";
}

type WebhookEventType =
	| "report.completed"
	| "report.failed"
	| "matching.completed"
	| "matching.failed";

type WebhookEvent<T = unknown> = {
	createdAt: string;
	data: T;
	id: string;
	timestamp: string;
	type: string;
};

type ReportCompletedData = {
	jobId: string;
	reportId: string;
	status: "succeeded";
};

type ReportFailedData = {
	error: {
		code: string;
		message: string;
	};
	jobId: string;
	status: "failed";
};

type MatchingCompletedData = {
	jobId: string;
	matchingId: string;
	status: "succeeded";
};

type MatchingFailedData = {
	error: {
		code: string;
		message: string;
	};
	jobId: string;
	status: "failed";
};

type ReportCompletedEvent = WebhookEvent<ReportCompletedData> & {
	type: "report.completed";
};

type ReportFailedEvent = WebhookEvent<ReportFailedData> & {
	type: "report.failed";
};

type MatchingCompletedEvent = WebhookEvent<MatchingCompletedData> & {
	type: "matching.completed";
};

type MatchingFailedEvent = WebhookEvent<MatchingFailedData> & {
	type: "matching.failed";
};

class WebhooksResource {
	async verifySignature(params: {
		payload: string;
		headers: Record<string, string | string[] | undefined>;
		secret: string;
		toleranceSec?: number;
	}): Promise<{ ok: true }> {
		const tolerance = params.toleranceSec ?? 300;
		const sigHeader = getHeader(params.headers, "conduit-signature");
		if (!sigHeader) {
			throw new WebhookVerificationError("Missing conduit-signature header", {
				code: "webhook_signature_missing",
			});
		}

		const sig = parseSignature(sigHeader);
		const ts = Number(sig.t);
		if (!Number.isFinite(ts)) {
			throw new WebhookVerificationError("Invalid signature timestamp", {
				code: "webhook_signature_invalid",
			});
		}

		const now = Math.floor(Date.now() / 1000);
		if (Math.abs(now - ts) > tolerance) {
			throw new WebhookVerificationError(
				"Signature timestamp outside tolerance",
				{ code: "webhook_signature_stale" },
			);
		}

		const expected = await hmacHex(params.secret, `${sig.t}.${params.payload}`);
		if (!timingSafeEqualHex(expected, sig.v1)) {
			throw new WebhookVerificationError("Invalid signature", {
				code: "webhook_signature_invalid",
			});
		}

		return { ok: true };
	}

	parseEvent(
		payload: string,
	):
		| ReportCompletedEvent
		| ReportFailedEvent
		| MatchingCompletedEvent
		| MatchingFailedEvent
		| WebhookEvent<unknown>;
	parseEvent<T = unknown>(payload: string): WebhookEvent<T>;
	parseEvent<T = unknown>(payload: string): WebhookEvent<T> {
		let raw: unknown;
		try {
			raw = JSON.parse(payload) as unknown;
		} catch (cause) {
			throw new ConduitError("Invalid webhook payload: invalid JSON", {
				cause,
				code: "invalid_webhook_payload",
			});
		}
		if (!isObject(raw)) {
			throw new ConduitError("Invalid webhook payload: not an object", {
				code: "invalid_webhook_payload",
			});
		}
		if (typeof raw.id !== "string") {
			throw new ConduitError("Invalid webhook payload: id must be a string", {
				code: "invalid_webhook_payload",
			});
		}
		if (typeof raw.type !== "string") {
			throw new ConduitError("Invalid webhook payload: type must be a string", {
				code: "invalid_webhook_payload",
			});
		}
		if (typeof raw.createdAt !== "string") {
			throw new ConduitError(
				"Invalid webhook payload: createdAt must be a string",
				{ code: "invalid_webhook_payload" },
			);
		}
		if (!isIsoTimestamp(raw.createdAt)) {
			throw new ConduitError(
				"Invalid webhook payload: createdAt must be an ISO8601 string",
				{ code: "invalid_webhook_payload" },
			);
		}
		if (typeof raw.timestamp !== "string") {
			throw new ConduitError(
				"Invalid webhook payload: timestamp must be a string",
				{ code: "invalid_webhook_payload" },
			);
		}
		if (!isIsoTimestamp(raw.timestamp)) {
			throw new ConduitError(
				"Invalid webhook payload: timestamp must be an ISO8601 string",
				{ code: "invalid_webhook_payload" },
			);
		}

		const data = "data" in raw ? raw.data : undefined;
		if (raw.type === "report.completed") {
			return {
				createdAt: raw.createdAt,
				data: parseReportCompletedData(data) as T,
				id: raw.id,
				timestamp: raw.timestamp,
				type: raw.type,
			};
		}

		if (raw.type === "report.failed") {
			return {
				createdAt: raw.createdAt,
				data: parseReportFailedData(data) as T,
				id: raw.id,
				timestamp: raw.timestamp,
				type: raw.type,
			};
		}

		if (raw.type === "matching.completed") {
			return {
				createdAt: raw.createdAt,
				data: parseMatchingCompletedData(data) as T,
				id: raw.id,
				timestamp: raw.timestamp,
				type: raw.type,
			};
		}

		if (raw.type === "matching.failed") {
			return {
				createdAt: raw.createdAt,
				data: parseMatchingFailedData(data) as T,
				id: raw.id,
				timestamp: raw.timestamp,
				type: raw.type,
			};
		}

		return {
			createdAt: raw.createdAt,
			data: data as T,
			id: raw.id,
			timestamp: raw.timestamp,
			type: raw.type,
		};
	}
}

function parseReportCompletedData(data: unknown): ReportCompletedData {
	if (!isObject(data)) {
		throw invalidPayloadError("Invalid report.completed data: not an object");
	}
	if (typeof data.jobId !== "string") {
		throw invalidPayloadError(
			"Invalid report.completed data: jobId must be a string",
		);
	}
	if (typeof data.reportId !== "string") {
		throw invalidPayloadError(
			"Invalid report.completed data: reportId must be a string",
		);
	}
	if (data.status !== "succeeded") {
		throw invalidPayloadError(
			"Invalid report.completed data: status must be succeeded",
		);
	}
	return { jobId: data.jobId, reportId: data.reportId, status: data.status };
}

function parseReportFailedData(data: unknown): ReportFailedData {
	if (!isObject(data)) {
		throw invalidPayloadError("Invalid report.failed data: not an object");
	}
	if (typeof data.jobId !== "string") {
		throw invalidPayloadError(
			"Invalid report.failed data: jobId must be a string",
		);
	}
	if (data.status !== "failed") {
		throw invalidPayloadError(
			"Invalid report.failed data: status must be failed",
		);
	}
	if (!isObject(data.error)) {
		throw invalidPayloadError(
			"Invalid report.failed data: error must be an object",
		);
	}
	if (typeof data.error.code !== "string") {
		throw invalidPayloadError(
			"Invalid report.failed data: error.code must be a string",
		);
	}
	if (typeof data.error.message !== "string") {
		throw invalidPayloadError(
			"Invalid report.failed data: error.message must be a string",
		);
	}
	return {
		error: {
			code: data.error.code,
			message: data.error.message,
		},
		jobId: data.jobId,
		status: data.status,
	};
}

function parseMatchingCompletedData(data: unknown): MatchingCompletedData {
	if (!isObject(data)) {
		throw invalidPayloadError("Invalid matching.completed data: not an object");
	}
	if (typeof data.jobId !== "string") {
		throw invalidPayloadError(
			"Invalid matching.completed data: jobId must be a string",
		);
	}
	if (typeof data.matchingId !== "string") {
		throw invalidPayloadError(
			"Invalid matching.completed data: matchingId must be a string",
		);
	}
	if (data.status !== "succeeded") {
		throw invalidPayloadError(
			"Invalid matching.completed data: status must be succeeded",
		);
	}
	return {
		jobId: data.jobId,
		matchingId: data.matchingId,
		status: data.status,
	};
}

function parseMatchingFailedData(data: unknown): MatchingFailedData {
	if (!isObject(data)) {
		throw invalidPayloadError("Invalid matching.failed data: not an object");
	}
	if (typeof data.jobId !== "string") {
		throw invalidPayloadError(
			"Invalid matching.failed data: jobId must be a string",
		);
	}
	if (data.status !== "failed") {
		throw invalidPayloadError(
			"Invalid matching.failed data: status must be failed",
		);
	}
	if (!isObject(data.error)) {
		throw invalidPayloadError(
			"Invalid matching.failed data: error must be an object",
		);
	}
	if (typeof data.error.code !== "string") {
		throw invalidPayloadError(
			"Invalid matching.failed data: error.code must be a string",
		);
	}
	if (typeof data.error.message !== "string") {
		throw invalidPayloadError(
			"Invalid matching.failed data: error.message must be a string",
		);
	}
	return {
		error: {
			code: data.error.code,
			message: data.error.message,
		},
		jobId: data.jobId,
		status: data.status,
	};
}

function invalidPayloadError(message: string): ConduitError {
	return new ConduitError(message, { code: "invalid_webhook_payload" });
}

function isIsoTimestamp(value: string): boolean {
	return !Number.isNaN(Date.parse(value));
}

function getHeader(
	headers: Record<string, string | string[] | undefined>,
	name: string,
): string | undefined {
	const key = Object.keys(headers).find(
		(k) => k.toLowerCase() === name.toLowerCase(),
	);
	if (!key) return;
	const value = headers[key];
	if (!value) return;
	if (Array.isArray(value)) return value[0];
	return value;
}

function parseSignature(value: string): { t: string; v1: string } {
	const out: Record<string, string> = {};
	for (const part of value.split(",")) {
		const [k, v] = part.split("=");
		if (!(k && v)) {
			throw invalidSignatureError("Invalid signature format");
		}
		const key = k.trim();
		if (key in out) {
			throw invalidSignatureError(
				"Invalid signature format: duplicate component",
			);
		}
		out[key] = v.trim();
	}
	if (!(out.t && out.v1)) {
		throw invalidSignatureError("Invalid signature format");
	}
	return { t: out.t, v1: out.v1 };
}

function invalidSignatureError(message: string): WebhookVerificationError {
	return new WebhookVerificationError(message, {
		code: "webhook_signature_invalid",
	});
}

async function hmacHex(secret: string, message: string): Promise<string> {
	const enc = new TextEncoder();
	const key = await crypto.subtle.importKey(
		"raw",
		enc.encode(secret),
		{ hash: "SHA-256", name: "HMAC" },
		false,
		["sign"],
	);
	const sig = await crypto.subtle.sign("HMAC", key, enc.encode(message));
	const bytes = new Uint8Array(sig);
	let out = "";
	for (const b of bytes) out += b.toString(16).padStart(2, "0");
	return out;
}

function timingSafeEqualHex(a: string, b: string): boolean {
	if (a.length !== b.length) return false;
	let diff = 0;
	for (let i = 0; i < a.length; i++) {
		diff |= a.charCodeAt(i) ^ b.charCodeAt(i);
	}
	return diff === 0;
}

export type {
	MatchingCompletedData,
	MatchingCompletedEvent,
	MatchingFailedData,
	MatchingFailedEvent,
	ReportCompletedData,
	ReportCompletedEvent,
	ReportFailedData,
	ReportFailedEvent,
	WebhookEvent,
	WebhookEventType,
};
export { WebhooksResource };
