import { z } from "zod";
import {
	reportSection,
	targetSelector as reportsTargetSelector,
} from "./reports";

const targetSelector = reportsTargetSelector;
const matchingContext = z.literal("behavioral_compatibility");

const subjectRef = z.discriminatedUnion("type", [
	z.object({
		entityId: z.string().min(1).max(256).trim(),
		type: z.literal("entity_id"),
	}),
	z.object({
		mediaId: z.string().min(1).max(256).trim(),
		selector: targetSelector,
		type: z.literal("media_target"),
	}),
]);
const entitySource = subjectRef;

const resolvedSubject = z.object({
	entityId: z.string().optional(),
	resolvedLabel: z.string().nullable().optional(),
	source: subjectRef,
});

const requestSubjects = z
	.object({
		group: z.array(subjectRef).min(1),
		target: subjectRef,
	})
	.strict();

const resolvedSubjects = z
	.object({
		group: z.array(resolvedSubject).min(1),
		target: resolvedSubject,
	})
	.strict();

const output = z
	.object({
		template: z.literal("matching"),
	})
	.strict();

const webhookConfig = z
	.object({
		headers: z.record(z.string(), z.string()).optional(),
		url: z.url(),
	})
	.optional();

const createJobBody = requestSubjects
	.extend({
		context: matchingContext,
		idempotencyKey: z.string().optional(),
		label: z.string().trim().min(1).max(64).optional(),
		webhook: webhookConfig,
	})
	.superRefine((data, ctx) => {
		const directEntityIds = new Set<string>();
		const directRefs = [data.target, ...data.group];

		for (const [index, item] of directRefs.entries()) {
			if (item.type !== "entity_id") {
				continue;
			}

			if (directEntityIds.has(item.entityId)) {
				const path = index === 0 ? ["target"] : ["group", index - 1];
				ctx.addIssue({
					code: z.ZodIssueCode.custom,
					message:
						"target and group must reference different direct entity IDs",
					path,
				});
				continue;
			}

			directEntityIds.add(item.entityId);
		}
	});

const jobReceipt = z.object({
	estimatedWaitSec: z.number().optional(),
	jobId: z.string(),
	stage: z.string().optional(),
	status: z.enum(["queued", "running"]),
});

const matchingAnalysisJson = z
	.object({
		schemaVersion: z.literal(1),
		sections: z.array(reportSection).min(1),
		summary: z.string().min(1),
		title: z.string().min(1),
	})
	.strict();

const matchingAnalysisResponse = z
	.object({
		context: matchingContext,
		createdAt: z.string(),
		group: z.array(resolvedSubject).min(1),
		id: z.string(),
		json: matchingAnalysisJson.nullish(),
		jobId: z.string().optional(),
		label: z.string().optional(),
		markdown: z.string().nullish(),
		output,
		target: resolvedSubject,
	})
	.strict();

const listQuery = z.object({
	entityId: z.string().optional(),
	limit: z.coerce.number().int().min(1).max(100).default(25),
	page: z.coerce.number().int().min(1).default(1),
	workspaceId: z.string(),
});

const listItem = z.object({
	createdAt: z.string(),
	group: z.array(resolvedSubject).min(1),
	id: z.string(),
	jobId: z.string().optional(),
	label: z.string().optional(),
	target: resolvedSubject,
});

const listResponse = z.object({
	items: z.array(listItem),
	pagination: z.object({
		limit: z.number().int().min(1),
		page: z.number().int().min(1),
		totalItems: z.number().int().min(0),
		totalPages: z.number().int().min(0),
	}),
});

const sharingStatus = z.object({
	active: z.boolean(),
	shareUrl: z.url().nullable(),
});

const toggleSharingBody = z.object({
	active: z.boolean(),
	workspaceId: z.string(),
});

const sharingQuery = z.object({
	workspaceId: z.string(),
});

function generateDefaultLabel(): string {
	const dateStr = new Date().toLocaleDateString("en-US", {
		day: "numeric",
		month: "short",
		year: "numeric",
	});
	return `Matching Analysis - ${dateStr}`;
}

type MatchingContext = z.infer<typeof matchingContext>;
type TargetSelector = z.infer<typeof targetSelector>;
type SubjectRef = z.infer<typeof subjectRef>;
type EntitySource = SubjectRef;
type ResolvedSubject = z.infer<typeof resolvedSubject>;
type RequestSubjects = z.infer<typeof requestSubjects>;
type ResolvedSubjects = z.infer<typeof resolvedSubjects>;
type CreateJobBody = z.infer<typeof createJobBody>;
type JobReceipt = z.infer<typeof jobReceipt>;
type MatchingAnalysisJson = z.infer<typeof matchingAnalysisJson>;
type MatchingAnalysisResponse = z.infer<typeof matchingAnalysisResponse>;
type ListQuery = z.infer<typeof listQuery>;
type ListItem = z.infer<typeof listItem>;
type ListResponse = z.infer<typeof listResponse>;
type SharingStatus = z.infer<typeof sharingStatus>;
type ToggleSharingBody = z.infer<typeof toggleSharingBody>;
type SharingQuery = z.infer<typeof sharingQuery>;

export type {
	CreateJobBody,
	EntitySource,
	JobReceipt,
	ListItem,
	ListQuery,
	ListResponse,
	MatchingAnalysisJson,
	MatchingAnalysisResponse,
	MatchingContext,
	RequestSubjects,
	ResolvedSubject,
	ResolvedSubjects,
	SharingQuery,
	SharingStatus,
	SubjectRef,
	TargetSelector,
	ToggleSharingBody,
};
export {
	createJobBody,
	type entitySource,
	generateDefaultLabel,
	jobReceipt,
	listItem,
	listQuery,
	listResponse,
	matchingAnalysisJson,
	matchingAnalysisResponse,
	matchingContext,
	output,
	requestSubjects,
	resolvedSubject,
	resolvedSubjects,
	sharingQuery,
	sharingStatus,
	subjectRef,
	targetSelector,
	toggleSharingBody,
	webhookConfig,
};
