import type { ReportResponse as ContractReportResponse } from "@mappa-ai/contracts/v1/reports";
import {
	jobReceipt,
	reportCreateJobBody,
	reportResponse,
} from "@mappa-ai/contracts/v1/reports";
import { ConduitError, InvalidSourceError } from "../errors";
import type {
	JobEvent,
	JobStage,
	Report,
	ReportCreateRequest,
	ReportForOutputType,
	ReportJobReceipt,
	ReportRunHandle,
	ReportSource,
	WaitOptions,
} from "../types";
import { randomId } from "../utils";
import type { FilesResource } from "./files";
import type { JobsResource } from "./jobs";
import type { Transport } from "./transport";
import { parseReq, parseRes } from "./validate";

class ReportsResource {
	private readonly transport: Transport;
	private readonly jobs: JobsResource;
	private readonly files: FilesResource;

	constructor(transport: Transport, jobs: JobsResource, files: FilesResource) {
		this.transport = transport;
		this.jobs = jobs;
		this.files = files;
	}

	async create(req: ReportCreateRequest): Promise<ReportJobReceipt> {
		validateTarget(req.target);
		const mediaId = await this.resolveSource(req.source, {
			idempotencyKey: req.idempotencyKey,
			requestId: req.requestId,
			signal: req.signal,
		});

		const idem = req.idempotencyKey ?? this.defaultIdempotencyKey();
		const body = parseReq(
			reportCreateJobBody,
			this.normalizeCreateRequest(req, mediaId),
			"reports.create body",
		);

		const res = await this.transport.request<Omit<ReportJobReceipt, "handle">>({
			body,
			idempotencyKey: idem,
			method: "POST",
			path: "/v1/reports/jobs",
			requestId: req.requestId,
			retryable: true,
			signal: req.signal,
		});

		const receiptData = parseRes(jobReceipt, res.data, "reports.createJob") as {
			estimatedWaitSec?: number;
			jobId: string;
			stage?: string;
			status: "queued" | "running";
		};
		const receipt: ReportJobReceipt = {
			...receiptData,
			mediaId,
			requestId: res.requestId ?? res.data.requestId,
			stage: toJobStage(receiptData.stage),
		};
		receipt.handle = this.handle(receipt.jobId);
		return receipt;
	}

	async get(
		reportId: string,
		opts?: { requestId?: string; signal?: AbortSignal },
	): Promise<Report> {
		const res = await this.transport.request<unknown>({
			method: "GET",
			path: `/v1/reports/${encodeURIComponent(reportId)}`,
			requestId: opts?.requestId,
			retryable: true,
			signal: opts?.signal,
		});
		return toReport(parseRes(reportResponse, res.data, "reports.get"));
	}

	private async getByJob(
		jobId: string,
		opts?: { requestId?: string; signal?: AbortSignal },
	): Promise<Report | null> {
		const res = await this.transport.request<unknown>({
			method: "GET",
			path: `/v1/reports/by-job/${encodeURIComponent(jobId)}`,
			requestId: opts?.requestId,
			retryable: true,
			signal: opts?.signal,
		});
		if (res.data === null) return null;
		return toReport(parseRes(reportResponse, res.data, "reports.getByJob"));
	}

	private handle(jobId: string): ReportRunHandle {
		return {
			cancel: () => this.jobs.cancel(jobId),
			job: () => this.jobs.get(jobId),
			jobId,
			report: () => this.getByJob(jobId) as Promise<ReportForOutputType | null>,
			stream: (opts?: {
				signal?: AbortSignal;
				onEvent?: (e: JobEvent) => void;
			}) => this.jobs.stream(jobId, opts),
			wait: async (opts?: WaitOptions): Promise<ReportForOutputType> => {
				const terminal = await this.jobs.wait(jobId, opts);
				if (!terminal.reportId) {
					throw new ConduitError(
						`Job ${jobId} succeeded but no reportId was returned`,
						{ code: "invalid_response" },
					);
				}
				return this.get(terminal.reportId) as Promise<ReportForOutputType>;
			},
		};
	}

	private defaultIdempotencyKey(): string {
		return randomId("idem");
	}

	private async resolveSource(
		source: ReportSource,
		opts: {
			idempotencyKey?: string;
			requestId?: string;
			signal?: AbortSignal;
		},
	): Promise<string> {
		const keys = ["mediaId", "file", "url", "path"].filter(
			(key) => key in source,
		);
		if (keys.length !== 1) {
			throw new InvalidSourceError(
				"source must include exactly one of mediaId, file, url, or path",
				{ code: "invalid_source" },
			);
		}

		if ("mediaId" in source) {
			if (!source.mediaId) {
				throw new InvalidSourceError(
					"source.mediaId must be a non-empty string",
					{ code: "invalid_source" },
				);
			}
			return source.mediaId;
		}

		if ("file" in source) {
			const upload = await this.files.upload({
				file: source.file,
				idempotencyKey: opts.idempotencyKey,
				label: source.label,
				requestId: opts.requestId,
				signal: opts.signal,
			});
			return upload.mediaId;
		}

		if ("path" in source) {
			const upload = await this.files.upload({
				idempotencyKey: opts.idempotencyKey,
				label: source.label,
				path: source.path,
				requestId: opts.requestId,
				signal: opts.signal,
			});
			return upload.mediaId;
		}

		const upload = await this.files.upload({
			idempotencyKey: opts.idempotencyKey,
			label: source.label,
			requestId: opts.requestId,
			signal: opts.signal,
			url: source.url,
		});
		return upload.mediaId;
	}

	private normalizeCreateRequest(
		req: ReportCreateRequest,
		mediaId: string,
	): Record<string, unknown> {
		return {
			entityLabel: req.entityLabel,
			idempotencyKey: req.idempotencyKey,
			label: req.label,
			media: { mediaId },
			output: req.output,
			target: normalizeTarget(req.target),
			webhook: req.webhook,
		};
	}
}

function normalizeTarget(
	target: ReportCreateRequest["target"],
): Record<string, unknown> {
	if (target.strategy === "dominant") {
		return {
			strategy: target.strategy,
			...(target.onMiss ? { on_miss: target.onMiss } : {}),
		};
	}

	if (target.strategy === "timerange") {
		return {
			strategy: target.strategy,
			...(target.onMiss ? { on_miss: target.onMiss } : {}),
			timerange: {
				end_seconds: target.timeRange?.endSeconds ?? null,
				start_seconds: target.timeRange?.startSeconds ?? null,
			},
		};
	}

	if (target.strategy === "entity_id") {
		return {
			strategy: target.strategy,
			...(target.onMiss ? { on_miss: target.onMiss } : {}),
			entity_id: target.entityId,
		};
	}

	if (target.strategy === "speaker_index") {
		return {
			strategy: target.strategy,
			...(target.onMiss ? { on_miss: target.onMiss } : {}),
			speaker_index: target.speakerIndex,
		};
	}

	return {
		strategy: target.strategy,
		...(target.onMiss ? { on_miss: target.onMiss } : {}),
		hint: target.hint,
	};
}

function validateTarget(target: ReportCreateRequest["target"]): void {
	if (target.strategy === "timerange") {
		validateTimerangeTarget(target.timeRange);
		return;
	}

	if (target.strategy === "entity_id" && !target.entityId.trim()) {
		throw new ConduitError("target.entityId is required for entity_id", {
			code: "invalid_request",
		});
	}

	if (
		target.strategy === "speaker_index" &&
		(!Number.isInteger(target.speakerIndex) || target.speakerIndex < 0)
	) {
		throw new ConduitError(
			"target.speakerIndex is required for speaker_index",
			{
				code: "invalid_request",
			},
		);
	}

	if (target.strategy === "magic_hint" && !target.hint.trim()) {
		throw new ConduitError("target.hint is required for magic_hint", {
			code: "invalid_request",
		});
	}
}

function validateTimerangeTarget(
	timeRange: { startSeconds?: number; endSeconds?: number } | undefined,
) {
	if (!timeRange) {
		throw new ConduitError("target.timeRange is required for timerange", {
			code: "invalid_request",
		});
	}

	const start = timeRange.startSeconds;
	const end = timeRange.endSeconds;
	if (start === undefined && end === undefined) {
		throw new ConduitError(
			"target.timeRange must include startSeconds or endSeconds",
			{ code: "invalid_request" },
		);
	}
	if (start !== undefined && end !== undefined && !(start < end)) {
		throw new ConduitError(
			"target.timeRange.startSeconds must be less than endSeconds",
			{ code: "invalid_request" },
		);
	}
}

function toJobStage(stage: string | undefined): JobStage | undefined {
	if (!stage) return;
	if (
		stage === "uploaded" ||
		stage === "queued" ||
		stage === "transcoding" ||
		stage === "extracting" ||
		stage === "scoring" ||
		stage === "rendering" ||
		stage === "finalizing"
	) {
		return stage;
	}
}

function toReport(report: ContractReportResponse): Report {
	return {
		createdAt: report.createdAt,
		entityId: report.entity?.id,
		entityLabel: report.entity?.label,
		id: report.id,
		jobId: report.jobId,
		label: report.label,
		mediaId: report.media.mediaId,
		provenance: report.provenance,
		output: {
			json: report.json ?? null,
			markdown: report.markdown ?? null,
			template: report.output.template,
		},
	};
}

export { ReportsResource };
