import { z } from "zod";

/**
 * Entities module Zod schemas and types.
 *
 * Provides workspace-scoped labels for speaker entities.
 * Labels allow workspaces to identify analyzed speakers with human-readable names.
 */
/**
 * Label validation schema.
 * - Max 64 characters
 * - Trimmed whitespace
 * - Free-form text (allows spaces, special characters)
 */
export const label = z
	.string()
	.trim()
	.min(1, "Label must be at least 1 character")
	.max(64, "Label must be at most 64 characters");

// ═══════════════════════════════════════════════════════════════════════════
// Query Parameters
// ═══════════════════════════════════════════════════════════════════════════

/**
 * Query parameters for listing entities.
 */
export const listEntitiesQuery = z.object({
	/** Cursor for pagination */
	cursor: z.string().optional(),
	/** Number of entities per page (1-100, default 20) */
	limit: z.coerce.number().min(1).max(100).default(20),
});
export type ListEntitiesQuery = z.infer<typeof listEntitiesQuery>;

// ═══════════════════════════════════════════════════════════════════════════
// Request Bodies
// ═══════════════════════════════════════════════════════════════════════════

/**
 * Request body for updating an entity (PATCH).
 */
export const updateEntityBody = z.object({
	/** Human-readable label for this entity (null to clear) */
	label: label.nullable().optional(),
});
export type UpdateEntityBody = z.infer<typeof updateEntityBody>;

// ═══════════════════════════════════════════════════════════════════════════
// Response Schemas
// ═══════════════════════════════════════════════════════════════════════════

/**
 * Single entity response with label and metadata.
 */
export const entityResponse = z.object({
	createdAt: z.iso.datetime(),
	id: z.string(),
	/** Workspace-scoped human-readable label */
	label: z.string().nullable(),
	/** When this entity was last seen in a processed media file */
	lastSeenAt: z.iso.datetime().nullable(),
	/** Number of media files where this entity appears */
	mediaCount: z.number(),
});
export type EntityResponse = z.infer<typeof entityResponse>;

/**
 * Paginated list of entities response.
 */
export const listEntitiesResponse = z.object({
	cursor: z.string().nullable(),
	entities: z.array(entityResponse),
	hasMore: z.boolean(),
});
export type ListEntitiesResponse = z.infer<typeof listEntitiesResponse>;
